   297→ * 함수 타입 생성
   298→ */
   299→export function createFunctionType(
   300→  paramTypes: Type[],
   301→  returnType: Type
   302→): Type {
   303→  return {
   304→    kind: "fn",
   305→    paramTypes,
   306→    returnType,
